#include <vector>
#include <queue>
#include <tuple>
#include <climits>

using namespace std;

long long solve(vector<vector<long long>> edges, vector<bool> online, long long k) {
    int n = online.size();
    vector<vector<pair<long long, long long>>> adj(n);
    for (auto& e : edges) {
        long long u = e[0];
        long long v = e[1];
        long long cost = e[2];
        adj[u].push_back({v, cost});
    }

    vector<long long> max_min(n, -LLONG_MAX);
    max_min[0] = LLONG_MAX;

    priority_queue<tuple<long long, long long, int>> pq;
    pq.push({-LLONG_MAX, 0, 0});

    while (!pq.empty()) {
        auto [neg_current_min, total_cost, u] = pq.top();
        pq.pop();

        long long current_min = -neg_current_min;

        if (current_min < max_min[u]) {
            continue;
        }

        if (u == n - 1) {
            return current_min;
        }

        for (auto& [v, cost] : adj[u]) {
            if (!online[v]) {
                continue;
            }

            long long new_total = total_cost + cost;
            if (new_total > k) {
                continue;
            }

            long long new_current_min = min(current_min, cost);

            if (new_current_min > max_min[v]) {
                max_min[v] = new_current_min;
                pq.push({-new_current_min, new_total, v});
            }
        }
    }

    return -1;
}

