```javascript
function solve(edges, online, k) {
    const n = online.length;
    const adj = Array.from({ length: n }, () => []);
    for (const [u, v, cost] of edges) {
        adj[u].push([v, cost]);
    }

    const max_min = new Array(n).fill(-Infinity);
    max_min[0] = Infinity;

    class PriorityQueue {
        constructor() {
            this.heap = [];
        }
        push(value) {
            this.heap.push(value);
            this.heapifyUp(this.heap.length - 1);
        }
        pop() {
            if (this.heap.length === 0) return null;
            const top = this.heap[0];
            this.heap[0] = this.heap.pop();
            this.heapifyDown(0);
            return top;
        }
        heapifyUp(index) {
            while (index > 0) {
                const parent = Math.floor((index - 1) / 2);
                if (this.heap[parent][0] <= this.heap[index][0]) break;
                [this.heap[parent], this.heap[index]] = [this.heap[index], this.heap[parent]];
                index = parent;
            }
        }
        heapifyDown(index) {
            const n = this.heap.length;
            while (index < n) {
                const left = 2 * index + 1;
                const right = 2 * index + 2;
                let smallest = index;
                if (left < n && this.heap[left][0] < this.heap[smallest][0]) smallest = left;
                if (right < n && this.heap[right][0] < this.heap[smallest][0]) smallest = right;
                if (smallest === index) break;
                [this.heap[index], this.heap[smallest]] = [this.heap[smallest], this.heap[index]];
                index = smallest;
            }
        }
        peek() {
            return this.heap[0];
        }
        isEmpty() {
            return this.heap.length === 0;
        }
    }

    const pq = new PriorityQueue();
    pq.push([-Infinity, 0, 0]);

    while (!pq.isEmpty()) {
        const [negCurrentMin, totalCost, u] = pq.pop();
        const currentMin = -negCurrentMin;

        if (currentMin < max_min[u]) continue;

        if (u === n - 1) return currentMin;

        for (const [v, cost] of adj[u]) {
            if (!online[v]) continue;
            const newTotal = totalCost + cost;
            if (newTotal > k) continue;
            const newCurrentMin = Math.min(currentMin, cost);
            if (newCurrentMin > max_min[v]) {
                max_min[v] = newCurrentMin;
                pq.push([-newCurrentMin, newTotal, v]);
            }
        }
    }

    return -1;
}
